package main

import (
    "fmt"
    "testing"
)

// ---- Code to test ----
type User struct {
    Name string
    Age  int
}

func (u User) IsAdult() bool {
    return u.Age >= 18
}

func (u User) CanDrink() bool {
    return u.Age >= 21
}

func (u User) CanRetire() bool {
    return u.Age >= 65
}

// ---- Tests ----
func TestUserIsAdult(t *testing.T) {
    tests := []struct {
        name     string
        age      int
        expected bool
    }{
        {"adult", 18, true},
        {"minor", 17, false},
    }

    for _, tt := range tests {
        t.Run(tt.name, func(t *testing.T) {
            u := User{Age: tt.age}
            result := u.IsAdult()
            if result != tt.expected {
                t.Errorf("IsAdult() for age %d = %v; want %v", tt.age, result, tt.expected)
            }
        })
    }
}

// ---- Coverage commands ----
// go test -cover
// go test -coverprofile=coverage.out
// go tool cover -html=coverage.out
// go tool cover -func=coverage.out

// ---- Coverage percentage ----
// 33.3% coverage (only IsAdult tested)

